import { useState, useEffect } from "react";
import axios from "axios";

function App() {
  const [isLogin, setIsLogin] = useState(false);
  const [courses, setCourses] = useState([]);
  const [enrolled, setEnrolled] = useState([]);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [progress, setProgress] = useState({});

  useEffect(() => {
    if (isLogin) {
      axios.get("http://localhost:5000/courses").then((res) => {
        setCourses(res.data);
      });

      axios.get("http://localhost:5000/enrolled").then((res) => {
        setEnrolled(res.data);
      });
    }
  }, [isLogin]);

  const handleLogin = () => setIsLogin(true);

  const handleEnroll = async (course) => {
    await axios.post("http://localhost:5000/enroll", { course });

    const res = await axios.get("http://localhost:5000/enrolled");
    setEnrolled(res.data);
  };

  const markComplete = (courseId) => {
    setProgress({
      ...progress,
      [courseId]: 100,
    });
  };

  // 🔐 LOGIN
  if (!isLogin) {
    return (
      <div style={styles.login}>
        <h2>LMS Login</h2>
        <button onClick={handleLogin}>Login</button>
      </div>
    );
  }

  // 📚 MAIN LAYOUT
  return (
    <div style={styles.main}>
      {/* SIDEBAR */}
      <div style={styles.sidebar}>
        <h3>My Courses</h3>

        {enrolled.map((course) => (
          <div
            key={course.id}
            style={styles.sidebarItem}
            onClick={() => setSelectedCourse(course)}
          >
            {course.title}
          </div>
        ))}
      </div>

      {/* CONTENT */}
      <div style={styles.content}>
        {!selectedCourse ? (
          <>
            <h2>All Courses</h2>

            <div style={styles.grid}>
              {courses.map((course) => {
                const isEnrolled = enrolled.find(
                  (c) => c.id === course.id
                );

                return (
                  <div key={course.id} style={styles.card}>
                    <h3>{course.title}</h3>
                    <p>{course.description}</p>

                    <button onClick={() => handleEnroll(course)}>
                      {isEnrolled ? "Enrolled ✅" : "Enroll"}
                    </button>
                  </div>
                );
              })}
            </div>
          </>
        ) : (
          <>
            <h2>{selectedCourse.title}</h2>

            <iframe
              width="700"
              height="400"
              src={selectedCourse.video}
              title="video"
            />

            <br /><br />

            <button onClick={() => markComplete(selectedCourse.id)}>
              Mark Complete ✅
            </button>

            <h3>
              Progress: {progress[selectedCourse.id] || 0}%
            </h3>

            <button onClick={() => setSelectedCourse(null)}>
              ⬅ Back
            </button>
          </>
        )}
      </div>
    </div>
  );
}

// 🎨 STYLES
const styles = {
  login: {
    textAlign: "center",
    marginTop: "100px",
  },
  main: {
    display: "flex",
  },
  sidebar: {
    width: "250px",
    height: "100vh",
    background: "#222",
    color: "white",
    padding: "20px",
  },
  sidebarItem: {
    padding: "10px",
    cursor: "pointer",
    borderBottom: "1px solid gray",
  },
  content: {
    flex: 1,
    padding: "20px",
  },
  grid: {
    display: "flex",
    gap: "20px",
  },
  card: {
    border: "1px solid gray",
    padding: "20px",
    borderRadius: "10px",
  },
};

export default App;
